#include<bits/stdc++.h>
using namespace std;
long long a[101],dp[101][2];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long x,y,k;
        scanf("%lld%lld%lld",&x,&y,&k);
        memset(a,127,sizeof(a));
        memset(dp,63,sizeof(dp));
        long long d=abs(x-y),m=0;
        for(long long i=d;i;m++)
        {
            i>>=1;
        }
        for(long long i=0;i<=k;i++)
        {
            scanf("%lld",&a[i]);
        }
        for(long long i=1;i<=m;i++)
        {
            a[i]=min(a[i],a[i-1]<<1);
        }
        if(d&1)
        {
            dp[0][0]=dp[0][1]=a[0];
        }
        else
        {
            dp[0][0]=0;
        }
        for(long long i=1;i<=m;i++)
        {
            if(d&(1<<i))
            {
                dp[i][0]=dp[i-1][0]+a[i];
                dp[i][1]=min(dp[i-1][1],dp[i-1][0]+a[i]);
            }
            else
            {
                dp[i][0]=min(dp[i-1][0],dp[i-1][1]+a[i]);
                dp[i][1]=dp[i-1][1]+a[i];
            }
        }
        printf("%lld\n",dp[m][0]);
    }
    return 0;
}
